solution_code:
#include <stdio.h>
#include <stdlib.h>

int **alloc_matrix(int rows, int cols) {
    int **mat = malloc(rows * sizeof(int *));
    if (!mat) return NULL;
    for (int i = 0; i < rows; i++) {
        mat[i] = malloc(cols * sizeof(int));
        if (!mat[i]) {
            for (int j = 0; j < i; j++) free(mat[j]);
            free(mat);
            return NULL;
        }
    }
    return mat;
}

void free_matrix(int **mat, int rows) {
    for (int i = 0; i < rows; i++)
        free(mat[i]);
    free(mat);
}

validation.test_code:
int **alloc_matrix(int rows, int cols);
void free_matrix(int **mat, int rows);

void test_alloc_returns_non_null(void) {
    int **mat = alloc_matrix(3, 4);
    TEST_ASSERT_NOT_NULL(mat);
    free_matrix(mat, 3);
}

void test_alloc_rows_non_null(void) {
    int **mat = alloc_matrix(3, 4);
    TEST_ASSERT_NOT_NULL(mat);
    TEST_ASSERT_NOT_NULL(mat[0]);
    TEST_ASSERT_NOT_NULL(mat[1]);
    TEST_ASSERT_NOT_NULL(mat[2]);
    free_matrix(mat, 3);
}

void test_alloc_store_values(void) {
    int **mat = alloc_matrix(3, 4);
    TEST_ASSERT_NOT_NULL(mat);
    mat[0][0] = 5; mat[1][2] = 10; mat[2][3] = 15;
    TEST_ASSERT_EQUAL_INT(5, mat[0][0]);
    TEST_ASSERT_EQUAL_INT(10, mat[1][2]);
    TEST_ASSERT_EQUAL_INT(15, mat[2][3]);
    free_matrix(mat, 3);
}

void test_alloc_sequential_fill(void) {
    int **mat = alloc_matrix(2, 3);
    TEST_ASSERT_NOT_NULL(mat);
    for (int i = 0; i < 2; i++)
        for (int j = 0; j < 3; j++)
            mat[i][j] = i * 3 + j;
    TEST_ASSERT_EQUAL_INT(0, mat[0][0]);
    TEST_ASSERT_EQUAL_INT(2, mat[0][2]);
    TEST_ASSERT_EQUAL_INT(3, mat[1][0]);
    TEST_ASSERT_EQUAL_INT(5, mat[1][2]);
    free_matrix(mat, 2);
}

int main(void) {
    RUN_TEST(test_alloc_returns_non_null);
    RUN_TEST(test_alloc_rows_non_null);
    RUN_TEST(test_alloc_store_values);
    RUN_TEST(test_alloc_sequential_fill);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

